import{_ as a,j as o,p as t,at as l}from"./chunks/framework.CFWbLlrS.js";const m=JSON.parse('{"title":"@satorijs/adapter-telegram","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/adapters/telegram.md","filePath":"zh-CN/adapters/telegram.md"}'),i={name:"zh-CN/adapters/telegram.md"};function r(s,e,n,d,p,c){return o(),t("div",null,[...e[0]||(e[0]=[l('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /adapters/telegram.md for this page in Markdown format</div><h1 id="satorijs-adapter-telegram" tabindex="-1">@satorijs/adapter-telegram <a class="header-anchor" href="#satorijs-adapter-telegram" aria-label="Permalink to “@satorijs/adapter-telegram”">​</a></h1><h2 id="接入方法" tabindex="-1">接入方法 <a class="header-anchor" href="#接入方法" aria-label="Permalink to “接入方法”">​</a></h2><ol><li>搜索 @botfather（有个官方认证的符号）并进入聊天界面</li><li>输入 <code>/start</code> 后，会出现一个使用菜单，你可以使用这里指令对你的机器人进行配置</li><li>要创建一个机器人，请点击 <code>/newbot</code>，并根据系统提示完成创建流程</li><li>使用 <code>/setprivacy</code> 关闭 Privacy Mode（设置为 DISABLED，不然机器人只能收到特定消息）</li><li>创建完毕后，你会获得一个 token（请注意不要泄露），将其作为机器人配置项即可使用</li></ol><p>参考文档：<a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>如果启动机器人后发现收不到不带 <code>/</code> 的消息，这很可能是由于 Privacy Mode 未开启。如果开启后仍然收不到消息，请尝试将机器人从群组中移除后重新加入。</p></div><h2 id="机器人选项" tabindex="-1">机器人选项 <a class="header-anchor" href="#机器人选项" aria-label="Permalink to “机器人选项”">​</a></h2><h3 id="options-protocol" tabindex="-1">options.protocol <a class="header-anchor" href="#options-protocol" aria-label="Permalink to “options.protocol”">​</a></h3><ul><li>可选值: server, polling</li></ul><p>要使用的协议类型。</p><h3 id="options-token" tabindex="-1">options.token <a class="header-anchor" href="#options-token" aria-label="Permalink to “options.token”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>机器人账户的令牌。</p><h3 id="options-slash" tabindex="-1">options.slash <a class="header-anchor" href="#options-slash" aria-label="Permalink to “options.slash”">​</a></h3><ul><li>类型: <code>boolean</code></li><li>默认值: <code>true</code></li></ul><p>是否启用斜杠指令。</p><h3 id="options-files-endpoint" tabindex="-1">options.files.endpoint <a class="header-anchor" href="#options-files-endpoint" aria-label="Permalink to “options.files.endpoint”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>文件请求的终结点。</p><h3 id="options-files-local" tabindex="-1">options.files.local <a class="header-anchor" href="#options-files-local" aria-label="Permalink to “options.files.local”">​</a></h3><ul><li>类型: <code>boolean</code></li><li>默认值: <code>false</code></li></ul><p>是否启用 <a href="https://github.com/tdlib/telegram-bot-api" target="_blank" rel="noreferrer">Telegram Bot API</a> 本地模式。</p><h2 id="http-配置项" tabindex="-1">HTTP 配置项 <a class="header-anchor" href="#http-配置项" aria-label="Permalink to “HTTP 配置项”">​</a></h2><h3 id="options-path" tabindex="-1">options.path <a class="header-anchor" href="#options-path" aria-label="Permalink to “options.path”">​</a></h3><ul><li>类型: <code>string</code></li><li>默认值: <code>&#39;/telegram&#39;</code></li></ul><p>服务器监听的路径。</p><h3 id="options-selfurl" tabindex="-1">options.selfUrl <a class="header-anchor" href="#options-selfurl" aria-label="Permalink to “options.selfUrl”">​</a></h3><ul><li>类型: <code>string</code></li></ul><p>服务暴露在公网的地址。</p>',29)])])}const f=a(i,[["render",r]]);export{m as __pageData,f as default};
